mapper.sql:
WHERE c.apt_cmplex_no = #{searchVO.aptCmplexNo}

    AND c.cvpl_ty_cd = #{searchVO.cvplTyCd}




            AND c.cvpl_stts_cd IN ('APLY', 'RCPT', 'POCS')


            AND c.cvpl_stts_cd = #{searchVO.cvplSttsCd}




    AND c.cvpl_reg_dt >= TO_DATE(#{searchVO.searchDateFrom}, 'YYYY-MM-DD')


    AND c.cvpl_reg_dt < TO_DATE(#{searchVO.searchDateTo}, 'YYYY-MM-DD') + 1


    AND (
    m.user_nm LIKE '%' || #{searchWord} || '%'
    OR c.cvpl_ttl LIKE '%' || #{searchWord} || '%'
    OR au.dong_nm || ' ' || ad.ho LIKE '%' || #{searchWord} || '%'
    )

mapper.insert:

    SELECT 'HSTRY' || LPAD(SEQ_CVPL_HSTRY.nextval, 6, '0')      /*kr.or.ddit.domain.apt.mgmtOffice.complaint.mapper.ManagerComplaintMapper.insertCvplHstry*/
    FROM dual

INSERT INTO cvpl_hstry (
cvpl_hstry_id
,cvpl_ans
,pic_id
,cvpl_stts_cd
,cvpl_no
) VALUES (
#{cvplHstryId}
,#{cvplAns}
,#{picId}
,#{cvplSttsCd}
,#{cvplNo}
)

mapper.update:
UPDATE cvpl
SET cvpl_stts_cd = #{cvplSttsCd}
,cvpl_mdf_dt  = SYSDATE

    ,cvpl_end_dt  = TO_DATE(#{cvplEndDt}, 'YYYY.MM.DD')

WHERE cvpl_no = #{cvplNo}
